class Solution {
 public String[] sortPeople(String[] names, int[] heights) {
        int n = names.length;
        String[] result = new String[n];
        Integer[] heightIndices = new Integer[n];
        for (int i = 0; i < n; i++) {
            heightIndices[i] = i;
        }
        Arrays.sort(heightIndices, (a, b) -> Integer.compare(heights[b], heights[a]));
        for (int i = 0; i < n; i++) {
            result[i] = names[heightIndices[i]];
        }
        return result;
 }
}
